sql:
SELECT nominal_dia, applied_load, reactive_pressure, material_id, product_line_id, quality_status
FROM fasteners
WHERE material_id = 1 AND product_line_id = 1 AND quality_status = 'Pass';

SELECT product_line_id
FROM fasteners
WHERE fastener_id = 0;

SELECT nominal_dia, applied_load, production_cost
FROM fasteners
WHERE material_id = (SELECT material_id FROM materials WHERE material_name = 'Aluminum');

SELECT nominal_dia, reactive_pressure, quality_status
FROM fasteners
WHERE reactive_pressure = (SELECT MAX(reactive_pressure) FROM fasteners);

external_knowledge:
- "Golden" in the production process refers to fasteners with a quality status of 'Pass';
- "Manufacturing birthday" refers to the manufacturing date;
- "Crossed the six-figure threshold" refers to a total production cost greater than $100,000.

sql:
SELECT AVG(production_cost) AS average_production_cost
FROM fasteners
WHERE quality_status = 'Pass';

SELECT fastener_type_name
FROM fastener_types
WHERE status = 'active';
